  value?.toString().trim().replace(/\s+/g, ' ').toUpperCase() ?? '';

const suggestionIsDifferent = (
  address: SupportProfileAddressPayload,
  suggestion: SmartySuggestedAddress | undefined
) => {
  if (!suggestion) {
    return false;
  }

  const comparisons: Array<[string | null | undefined, string | null | undefined]> = [
    [address.line1, suggestion.delivery_line_1],
    [address.city, suggestion.components.city_name],
